    64	    const svg = d3.select(svgRef.current);
    65	    const width = svgRef.current.clientWidth;
    66	    const height = svgRef.current.clientHeight;
    67	    const margin = { top: 10, right: 10, bottom: 20, left: 30 };
    68	
    69	    svg.selectAll("*").remove();
    70	
    71	    const x = d3.scaleTime()
    72	      .domain(d3.extent(data, d => new Date(d.timestamp)) as [Date, Date])
    73	      .range([margin.left, width - margin.right]);
    74	
    75	    const y = d3.scaleLinear()
    76	      .domain([0, d3.max(data, d => Math.max(d.optimized, d.active)) || 10])
    77	      .nice()
    78	      .range([height - margin.bottom, margin.top]);
    79	
    80	    // Area for Optimized
    81	    const areaOptimized = d3.area<any>()
    82	      .x(d => x(new Date(d.timestamp)))
    83	      .y0(height - margin.bottom)
    84	      .y1(d => y(d.optimized))
    85	      .curve(d3.curveMonotoneX);
    86	
    87	    svg.append("path")
    88	      .datum(data)
    89	      .attr("fill", "rgba(242, 125, 38, 0.1)")
