    94	      .x(d => x(new Date(d.timestamp)))
    95	      .y(d => y(d.optimized))
    96	      .curve(d3.curveMonotoneX);
    97	
    98	    const lineActive = d3.line<any>()
    99	      .x(d => x(new Date(d.timestamp)))
   100	      .y(d => y(d.active))
   101	      .curve(d3.curveMonotoneX);
   102	
   103	    // Grid lines
   104	    svg.append("g")
   105	      .attr("class", "grid")
   106	      .attr("transform", `translate(0,${height - margin.bottom})`)
   107	      .call(d3.axisBottom(x).ticks(5).tickSize(-height + margin.top + margin.bottom).tickFormat("" as any))
   108	      .attr("stroke-opacity", 0.05)
   109	      .attr("color", "#fff");
   110	
   111	    svg.append("g")
   112	      .attr("class", "grid")
   113	      .attr("transform", `translate(${margin.left},0)`)
   114	      .call(d3.axisLeft(y).ticks(5).tickSize(-width + margin.left + margin.right).tickFormat("" as any))
   115	      .attr("stroke-opacity", 0.05)
   116	      .attr("color", "#fff");
